CREATE TRIGGER [dbo].[ContainerOrderItemUnit_History]ON [dbo].[ContainerOrderItemUnit]AFTER INSERT, UPDATE, DELETE ASDECLARE @HistoryAction CHAR(1)set @HistoryAction = (SELECT TOP 1 	CASE 		WHEN i.ContainerOrderItemUnitId IS NOT NULL AND d.ContainerOrderItemUnitId IS NULL THEN 'I' 		WHEN i.ContainerOrderItemUnitId IS NOT NULL AND d.ContainerOrderItemUnitId IS NOT NULL THEN 'U' 		WHEN i.ContainerOrderItemUnitId IS NULL AND d.ContainerOrderItemUnitId IS NOT NULL THEN 'D'		ELSE 'NA'	END AS HistoryActionfrom inserted as i	full outer join deleted as d on i.ContainerOrderItemUnitId = d.ContainerOrderItemUnitId)IF @HistoryAction = 'I' OR @HistoryAction = 'U'BEGIN	INSERT INTO History.dbo_ContainerOrderItemUnit([ContainerOrderItemUnitId], [ContainerId], [OrderItemUnitId], [PositionOnContainer], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [ContainerOrderItemUnitId], [ContainerId], [OrderItemUnitId], [PositionOnContainer], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction 	FROM insertedENDELSE IF @HistoryAction = 'D'BEGIN	INSERT INTO History.dbo_ContainerOrderItemUnit([ContainerOrderItemUnitId], [ContainerId], [OrderItemUnitId], [PositionOnContainer], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [ContainerOrderItemUnitId], [ContainerId], [OrderItemUnitId], [PositionOnContainer], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction  	FROM deletedEND